# ========================= ICON MÈO CHO GIAO DIỆN =========================
CAT_ICON_MIME = "png"
CAT_ICON_SEARCH_B64 = """"""
CAT_ICON_FIT_B64 = """"""
CAT_ICON_MEMORY_B64 = """"""
CAT_ICON_JOBSTART_B64 = """"""
CAT_ICON_INTERVIEW_B64 = """"""

def _cat_icon_data_url(kind: str):
    mapping = {
        "search": CAT_ICON_SEARCH_B64,
        "fit": CAT_ICON_FIT_B64,
        "memory": CAT_ICON_MEMORY_B64,
        "jobstart": CAT_ICON_JOBSTART_B64,
        "interview": CAT_ICON_INTERVIEW_B64,
    }
    return f"data:image/{CAT_ICON_MIME};base64,{mapping[kind]}"
# ======================= HẾT PHẦN ICON MÈO CHO GIAO DIỆN =======================


